<!DOCTYPE html>
<html>
  <head>
    <title><%= @post.title %></title>
    <style>
      /* Add your CSS styles here */
    </style>
  </head>
  
  <body>
    <h1><%= @post.title %></h1>
    <p><strong><%= @post.author %></strong> - <em><%= @post.created_at.strftime("%B %d, %Y") %></em></p>
    
